#include <stdio.h>
#include <stdlib.h>

// Node structure for the binary tree
struct Node {
    int val;
    struct Node* left;
    struct Node* right;
};

// Function to create a new node
struct Node* createNode(int val) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to calculate the height of a subtree
int calculateHeight(struct Node* node) {
    if (node == NULL) {
        return 0;
    }

    // Recursively calculate the height of left and right subtrees
    int leftHeight = calculateHeight(node->left);
    int rightHeight = calculateHeight(node->right);

    // Return the height of the current subtree
    return 1 + (leftHeight > rightHeight ? leftHeight : rightHeight);
}

// Function to calculate the diameter of a binary tree
int diameterOfBinaryTree(struct Node* root) {
    if (root == NULL) {
        return 0;
    }

    // Calculate the height of left and right subtrees
    int leftHeight = calculateHeight(root->left);
    int rightHeight = calculateHeight(root->right);

    // Calculate the diameter of the current node
    int diameter = leftHeight + rightHeight;

    // Recursively calculate the diameter of left and right subtrees
    int leftDiameter = diameterOfBinaryTree(root->left);
    int rightDiameter = diameterOfBinaryTree(root->right);

    // Return the maximum diameter
    return (diameter > leftDiameter && diameter > rightDiameter) ? diameter : (leftDiameter > rightDiameter ? leftDiameter : rightDiameter);
}

int main() {
    // Creating a sample binary tree
    struct Node* root = createNode(1);
    root->left = createNode(2);
    root->right = createNode(3);
    root->left->left = createNode(4);
    root->left->right = createNode(5);
    root->left->right->right = createNode(6);
    root->left->right->right->right = createNode(7);

    // Calculate the diameter of the binary tree
    int diameter = diameterOfBinaryTree(root);

    printf("The diameter of the binary tree is: %d\n", diameter);

    return 0;
}

